  partial: {
    icon: AlertCircle,
    iconColor: 'text-amber-500',
    badge: 'badge-partial',
    badgeLabel: '⚠ Partial',
    borderClass: 'criterion-partial',
    expandBg: 'bg-amber-50/60',
