  fail: {
    icon: XCircle,
    iconColor: 'text-red-500',
    badge: 'badge-fail',
    badgeLabel: '✗ Fail',
    borderClass: 'criterion-fail',
    expandBg: 'bg-red-50/50',
  },
}

